 private static final String kCARuleSet = "CashAssistanceRuleSet";
  private static final String kCADualDetectionRuleClass =
    "CADualDetectionCalculator";
  private static final String kisDualDetectedTimeline =
    "isDualDetectedTimeline";
 @Override
  public Timeline<Boolean> getDualTimeline(final Session session,
    final DualParams p) throws AppException, InformationalException {
    final RuleObject caDualDetectionRuleObject =
      createCADualDetectionCalculator(session, p);
    specifyBatchSpecificParameters(caDualDetectionRuleObject, p);
    @SuppressWarnings("unchecked")
    final Timeline<Boolean> dualTimeline =
      (Timeline<Boolean>) caDualDetectionRuleObject
        .getAttributeValue(kisDualDetectedTimeline).getValue();
    return dualTimeline;
  }
  /**
   * Create the RuleObject for ISCashAssistanceRuleSet.CADualDetectionCalculator
   * initializing with the required attributes.
   *
   * @param session Session.
   * @param p DualParams
   * @return RuleObject.
   */
  private RuleObject createCADualDetectionCalculator(final Session session,
    final DualParams p) {
    final RuleClass caDualDetectionRuleClass =
      readRuleClass(kCARuleSet, kCADualDetectionRuleClass);
    final RuleObject caseParticipantRole =
      createCaseParticipantRole(session, p);
    final RuleObject memberCPRCalculator =
      createMemberCPRCalculator(session, caseParticipantRole);
    final RuleObject caDualDetectionRuleObject =
      session.createRuleObject(caDualDetectionRuleClass, memberCPRCalculator);
    return caDualDetectionRuleObject;
  }
  /**
   * Species attributes specific to the batch run on to the
   * CADualDetectionCalculator RuleObject.
   *
   * @param caDualDetectionRuleObject RuleObject CADualDetectionCalculator
   * @param p DualParams p
   */
  private void specifyBatchSpecificParameters(
    final RuleObject caDualDetectionRuleObject, final DualParams p) {
    setDualDetectionStartDate(caDualDetectionRuleObject,
      p.dualDetectionStartDate);
  }
